    underscore_positions = [i for i, c in enumerate(s) if c == '_']
    x_values = range(10) if not x_positions else range(10)
    underscore_values = [range(10) for _ in underscore_positions]

    for x_val in x_values:
        temp = list(s)
        for pos in x_positions:
            temp[pos] = str(x_val)
        if underscore_positions:
            for values in product(*underscore_values):
                temp2 = temp.copy()
                for i, pos in enumerate(underscore_positions):
