    if not x:
        return False
    if x[0] == '0' and len(x) > 1:
        return False
    return int(x) % 25 == 0

def generate_numbers(s):
    x_positions = [i for i, c in enumerate(s) if c == 'X']
    underscore_positions = [i for i, c in enumerate(s) if c == '_']
    x_values = range(10) if x_positions else [None]
    underscore_values = [range(10) for _ in underscore_positions] if underscore_positions else [None]

    for x_val in x_values:
        if x_positions and x_val is None:
            continue
        temp_s = list(s)
        if x_positions:
            for pos in x_positions:
                temp_s[pos] = str(x_val)
        underscore_val_product = itertools.product(*underscore_values) if underscore_positions else [None]
        for us_vals in underscore_val_product:
            if underscore_positions and us_vals is None:
                continue
            current = temp_s.copy()
            if underscore_positions:
                for pos, val in zip(underscore_positions, us_vals):
                    current[pos] = str(val)
            candidate = ''.join(current)
            if is_valid(candidate):
                yield candidate

unique_numbers = set()
for num in generate_numbers(s):
    unique_numbers.add(num)

